3_real_world_example.code:
const elementData = new WeakMap();

function trackElement(el) {
  elementData.set(el, 'Secret metadata for this button');
}

let btn = document.getElementById('myBtn');
trackElement(btn);

// Later, the user navigates away and the button is destroyed.
btn.remove();
btn = null;

// Because we used a WeakMap, the 'Secret metadata' is 
// automatically deleted from memory! 
// If we used a normal Map, it would sit in memory forever causing a leak.

